import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { AlertTriangle, Eye, EyeOff } from 'lucide-react';

export default function LoginPage() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [showPw, setShowPw] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const user = await login(form.email, form.password);
      toast.success(`Welcome back, ${user.name}!`);
      navigate(user.role === 'authority' ? '/authority' : '/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Login failed');
    } finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight:'calc(100vh - 60px)', display:'flex', alignItems:'center', justifyContent:'center', padding:24 }}>
      <div className="card fade-up" style={{ width:'100%', maxWidth:420 }}>
        <div style={{ textAlign:'center', marginBottom:28 }}>
          <div style={{ display:'inline-flex', background:'var(--accent-glow)', borderRadius:12, padding:'10px', marginBottom:14 }}>
            <AlertTriangle size={24} color="var(--accent)"/>
          </div>
          <h2 style={{ fontSize:24, marginBottom:6 }}>Welcome back</h2>
          <p style={{ color:'var(--text-muted)', fontSize:14 }}>Sign in to your RoadAlert account</p>
        </div>

        <form onSubmit={handleSubmit} style={{ display:'flex', flexDirection:'column', gap:16 }}>
          <div className="form-group">
            <label className="form-label">Email</label>
            <input className="form-input" type="email" placeholder="you@example.com"
              value={form.email} onChange={e=>setForm({...form, email:e.target.value})} required/>
          </div>
          <div className="form-group">
            <label className="form-label">Password</label>
            <div style={{ position:'relative' }}>
              <input className="form-input" type={showPw?'text':'password'} placeholder="••••••••"
                style={{ paddingRight:42 }}
                value={form.password} onChange={e=>setForm({...form, password:e.target.value})} required/>
              <button type="button" onClick={()=>setShowPw(!showPw)}
                style={{ position:'absolute', right:12, top:'50%', transform:'translateY(-50%)', background:'none', border:'none', color:'var(--text-muted)', display:'flex' }}>
                {showPw ? <EyeOff size={16}/> : <Eye size={16}/>}
              </button>
            </div>
          </div>
          <button type="submit" className="btn btn-primary" style={{ width:'100%', justifyContent:'center', padding:'12px' }} disabled={loading}>
            {loading ? 'Signing in…' : 'Sign In'}
          </button>
        </form>

        {/* Default credentials hint */}
        <div style={{ marginTop:20, padding:'14px', background:'var(--bg)', borderRadius:8, border:'1px solid var(--border)' }}>
          <p style={{ fontSize:12, color:'var(--text-muted)', marginBottom:6, fontWeight:600, textTransform:'uppercase', letterSpacing:'0.05em' }}>Default Authority Account</p>
          <p style={{ fontSize:13, color:'var(--text-faint)' }}>Email: <span style={{ color:'var(--text)' }}>authority@roadalert.gov</span></p>
          <p style={{ fontSize:13, color:'var(--text-faint)' }}>Password: <span style={{ color:'var(--text)' }}>Admin@1234</span></p>
        </div>

        <p style={{ textAlign:'center', marginTop:18, fontSize:14, color:'var(--text-muted)' }}>
          New user? <Link to="/register" style={{ color:'var(--accent)', fontWeight:600 }}>Create account</Link>
        </p>
      </div>
    </div>
  );
}
